    >
      <div className="container mx-auto flex items-center justify-center gap-2">
        <Tag size={14} />
        <span>{t('promo.firstOrder', '─É╞ín h├áng ─æß║ºu ti├¬n: Giß║úm 10% vß╗¢i m├ú')} <strong>NEWUSER10</strong></span>
        <button onClick={() => { setDismissed(true); localStorage.setItem('vnvt_first_order_dismissed', 'true'); }} className="ml-2 text-white/60 hover:text-white text-xs">Γ£ò</button>
      </div>
    </motion.div>
