};

// ============ #53 Tiered Discounts Display ============
export const TieredDiscounts = ({ quantity }: { quantity: number }) => {
  const tiers = [
    { min: 2, discount: 5, label: 'Mua 2+ giß║úm 5%' },
    { min: 5, discount: 10, label: 'Mua 5+ giß║úm 10%' },
    { min: 10, discount: 15, label: 'Mua 10+ giß║úm 15%' },
  ];

  const activeTier = tiers.filter(t => quantity >= t.min).pop();

  return (
    <div className="flex flex-wrap gap-1.5">
