  const handleBuyNow = async () => {
    if (hasFixedPrice && !isOutOfStock) {
      setIsAddingToCart(true);
      try {
        await addToCart(product, quantity);
        toast.success(t('product.addToCartSuccess') || '─É├ú th├¬m v├áo giß╗Å h├áng');
