            <th className="text-right p-3 font-semibold">Gi├í</th>
            <th className="text-right p-3 font-semibold">Tß╗ôn kho</th>
          </tr>
        </thead>
        <tbody>
          {items.map((p) => (
            <tr key={p.code} className={`border-b ${changed.has(p.code) ? 'bg-yellow-50' : 'hover:bg-hover'}`}>
