                <h2 className="text-lg font-bold">{t('sizeGuide.title', 'H╞░ß╗¢ng dß║½n chß╗ìn size')}</h2>
              </div>
              <button onClick={onClose} className="p-1 hover:bg-black/10 rounded-lg transition-colors">
                <X size={20} />
              </button>
            </div>

            {/* Input */}
            <div className="p-5">
              <div className="grid grid-cols-2 gap-4 mb-6">
                <div>
                  <label className="block text-sm font-medium mb-1.5">{t('sizeGuide.height', 'Chiß╗üu cao (cm)')}</label>
                  <input
                    type="number"
                    value={height}
                    onChange={(e) => setHeight(e.target.value)}
                    placeholder="170"
                    min="140" max="210"
                    className="w-full px-3 py-2.5 border rounded-xl focus:outline-none focus:border-indigo-500 bg-secondary text-sm"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium mb-1.5">{t('sizeGuide.weight', 'C├ón nß║╖ng (kg)')}</label>
                  <input
                    type="number"
                    value={weight}
                    onChange={(e) => setWeight(e.target.value)}
                    placeholder="65"
                    min="30" max="150"
                    className="w-full px-3 py-2.5 border rounded-xl focus:outline-none focus:border-indigo-500 bg-secondary text-sm"
                  />
                </div>
              </div>

              {/* Recommendation */}
              {recommendation && (
                <motion.div
                  initial={{ y: 10, opacity: 0 }}
                  animate={{ y: 0, opacity: 1 }}
                  className="p-4 bg-green-50 dark:bg-green-950/30 border border-green-200 dark:border-green-800 rounded-xl mb-6"
                >
                  <div className="flex items-center gap-2 mb-2">
                    <Info size={16} className="text-green-600" />
                    <span className="text-sm font-medium text-green-800 dark:text-green-300">
                      {t('sizeGuide.recommended', 'Size gß╗úi ├╜ cho bß║ín')}
                    </span>
                  </div>
                  <div className="text-3xl font-bold text-green-700 dark:text-green-400">
                    {recommendation.size}
                  </div>
                </motion.div>
              )}

              {/* Size Chart Table */}
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="border-b">
                      <th className="text-left py-2 px-2 font-semibold">Size</th>
                      <th className="text-left py-2 px-2 font-semibold">{t('sizeGuide.height', 'Chiß╗üu cao')}</th>
                      <th className="text-left py-2 px-2 font-semibold">{t('sizeGuide.weight', 'C├ón nß║╖ng')}</th>
                      {productType === 'clothing' && (
                        <>
                          <th className="text-left py-2 px-2 font-semibold">{t('sizeGuide.chest', 'Ngß╗▒c')}</th>
                          <th className="text-left py-2 px-2 font-semibold">{t('sizeGuide.waist', 'Eo')}</th>
                        </>
                      )}
                      {productType === 'shoes' && (
                        <th className="text-left py-2 px-2 font-semibold">{t('sizeGuide.foot', 'Ch├ón')}</th>
                      )}
                    </tr>
                  </thead>
                  <tbody>
                    {(SIZE_CHART[productType === 'shoes' ? 'shoes' : 'clothing']).map((row) => (
                      <tr
                        key={row.size}
