                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
};

import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { Eye, TrendingUp, ShoppingBag } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

interface SocialProofProps {
    productId: string;
    initialViewers?: number | undefined;
    initialSold?: number | undefined;
    className?: string;
}

export const SocialProof: React.FC<SocialProofProps> = ({ 
    productId, 
    initialViewers = 0, 
    initialSold = 0, 
    className 
}) => {
    const { t } = useTranslation();
    const [viewers, setViewers] = useState(initialViewers || 0);
    const [sold24h, setSold24h] = useState(initialSold || 0);
    const [activeMsg, setActiveMsg] = useState(0);

    useEffect(() => {
        // If initial values are 0, use a fallback based on hash to avoid empty look, 
        // but real data takes precedence.
        const hash = productId.split('').reduce((acc, char) => acc + char.charCodeAt(0), 0);
        const baseViewers = initialViewers > 0 ? initialViewers : 10 + (hash % 40);
        const baseSold = initialSold > 0 ? initialSold : 2 + (hash % 15);

        setViewers(baseViewers);
        setSold24h(baseSold);

        // Fluctuate viewers
        const interval = setInterval(() => {
            setViewers(prev => {
                const change = Math.floor(Math.random() * 5) - 2; // -2 to +2
                return Math.max(5, prev + change);
            });
        }, 5000);

        // Rotate messages
        const msgInterval = setInterval(() => {
            setActiveMsg(prev => (prev + 1) % 3);
        }, 8000);

        return () => {
            clearInterval(interval);
            clearInterval(msgInterval);
        };
    }, [productId]);

    const messages = [
        {
            icon: Eye,
            text: t('product.social.viewing', '{{count}} ng╞░ß╗¥i ─æang xem sß║ún phß║⌐m n├áy', { count: viewers }),
            color: 'text-indigo-600 dark:text-indigo-400',
            bg: 'bg-indigo-50 dark:bg-indigo-900/20'
        },
        {
            icon: ShoppingBag,
            text: t('product.social.sold24h', '─É├ú b├ín {{count}} c├íi trong 24h qua', { count: sold24h }),
            color: 'text-emerald-600 dark:text-emerald-400',
            bg: 'bg-emerald-50 dark:bg-emerald-900/20'
        },
        {
            icon: TrendingUp,
            text: t('product.social.trending', 'Sß║ún phß║⌐m ─æang b├ín chß║íy!'),
            color: 'text-rose-600 dark:text-rose-400',
            bg: 'bg-rose-50 dark:bg-rose-900/20'
        }
    ];

    const current = messages[activeMsg];

    return (
        <div className={`h-8 overflow-hidden ${className}`}>
            <AnimatePresence mode="wait">
                <motion.div
                    key={activeMsg}
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, y: -20 }}
                    className={`inline-flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-bold ${current.bg} ${current.color}`}
                >
                    <current.icon size={14} className="animate-pulse" />
                    <span>{current.text}</span>
                </motion.div>
            </AnimatePresence>
        </div>
    );
};

/**
 * Feature #56: Gamified Spin-to-Win Coupon Wheel
 * Self-contained, uses localStorage for state management.
 */
import { useState, useRef, useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Gift, Copy, Check } from 'lucide-react';

const SPIN_KEY = 'vnvt_spin_result';

interface WheelSegment {
  label: string;
  code: string;
  color: string;
  probability: number;
}

const SEGMENTS: WheelSegment[] = [
  { label: 'Giß║úm 5%', code: 'SPIN5', color: '#6366f1', probability: 25 },
  { label: 'Giß║úm 10%', code: 'SPIN10', color: '#8b5cf6', probability: 20 },
  { label: 'Giß║úm 15%', code: 'SPIN15', color: '#a855f7', probability: 15 },
  { label: 'Giß║úm 20%', code: 'SPIN20', color: '#d946ef', probability: 8 },
  { label: 'FreeShip', code: 'FREESHIP', color: '#ec4899', probability: 12 },
  { label: 'Thß╗¡ lß║íi', code: '', color: '#f43f5e', probability: 20 },
];

function getWeightedRandom(): number {
  const total = SEGMENTS.reduce((sum, s) => sum + s.probability, 0);
  let random = Math.random() * total;
  for (let i = 0; i < SEGMENTS.length; i++) {
    random -= SEGMENTS[i].probability;
    if (random <= 0) return i;
  }
  return SEGMENTS.length - 1;
}

export const SpinToWin = ({ 
  isOpen, 
  onClose 
}: { 
  isOpen: boolean; 
  onClose: () => void;
}) => {
  const { t } = useTranslation();
  const [spinning, setSpinning] = useState(false);
  const [result, setResult] = useState<WheelSegment | null>(null);
  const [rotation, setRotation] = useState(0);
  const [copied, setCopied] = useState(false);
  const hasSpun = !!localStorage.getItem(SPIN_KEY);

  const handleSpin = useCallback(() => {
    if (spinning || hasSpun) return;
    
    const winnerIdx = getWeightedRandom();
    const segmentAngle = 360 / SEGMENTS.length;
    // Calculate rotation to land on the winning segment
    const targetAngle = 360 - (winnerIdx * segmentAngle + segmentAngle / 2);
    const totalRotation = rotation + 1440 + targetAngle; // 4 full spins + offset
    
    setSpinning(true);
    setRotation(totalRotation);
    
    setTimeout(() => {
      setSpinning(false);
      setResult(SEGMENTS[winnerIdx]);
      if (SEGMENTS[winnerIdx].code) {
        localStorage.setItem(SPIN_KEY, JSON.stringify(SEGMENTS[winnerIdx]));
      }
    }, 4000);
  }, [spinning, hasSpun, rotation]);

  const handleCopy = useCallback(() => {
    if (result?.code) {
      navigator.clipboard.writeText(result.code);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  }, [result]);

  const segmentAngle = 360 / SEGMENTS.length;

  return (
    <AnimatePresence>
      {isOpen && (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4"
          onClick={onClose}
        >
          <motion.div
            initial={{ scale: 0.8 }}
            animate={{ scale: 1 }}
            exit={{ scale: 0.8 }}
            onClick={(e) => e.stopPropagation()}
            className="relative w-full max-w-md bg-gradient-to-b from-indigo-900 to-purple-900 rounded-3xl p-6 text-white shadow-2xl"
          >
            <button onClick={onClose} className="absolute top-4 right-4 p-1 hover:bg-white/20 rounded-full z-10">
              <X size={20} />
            </button>

            <div className="text-center mb-6">
              <Gift size={24} className="mx-auto mb-2" />
              <h2 className="text-xl font-bold">{t('spin.title', 'V├▓ng quay may mß║»n!')}</h2>
              <p className="text-sm text-white/60">{t('spin.desc', 'Quay ─æß╗â nhß║¡n ╞░u ─æ├úi hß║Ñp dß║½n')}</p>
            </div>

            {/* Wheel */}
            <div className="relative w-64 h-64 mx-auto mb-6">
              {/* Pointer */}
              <div className="absolute -top-2 left-1/2 -translate-x-1/2 z-10 w-0 h-0 border-l-[12px] border-r-[12px] border-t-[20px] border-transparent border-t-yellow-400 drop-shadow-lg" />
              
              {/* Spinning wheel using CSS */}
              <div 
                className="w-full h-full rounded-full overflow-hidden border-4 border-yellow-400 shadow-2xl"
                style={{
                  transform: `rotate(${rotation}deg)`,
                  transition: spinning ? 'transform 4s cubic-bezier(0.17, 0.67, 0.12, 0.99)' : undefined,
                }}
              >
                <svg viewBox="0 0 200 200" className="w-full h-full">
                  {SEGMENTS.map((seg, i) => {
                    const startAngle = (i * segmentAngle * Math.PI) / 180;
                    const endAngle = ((i + 1) * segmentAngle * Math.PI) / 180;
                    const x1 = 100 + 100 * Math.cos(startAngle);
                    const y1 = 100 + 100 * Math.sin(startAngle);
                    const x2 = 100 + 100 * Math.cos(endAngle);
                    const y2 = 100 + 100 * Math.sin(endAngle);
                    const largeArc = segmentAngle > 180 ? 1 : 0;
                    const midAngle = ((i + 0.5) * segmentAngle * Math.PI) / 180;
                    const tx = 100 + 60 * Math.cos(midAngle);
                    const ty = 100 + 60 * Math.sin(midAngle);

                    return (
                      <g key={i}>
                        <path
                          d={`M100,100 L${x1},${y1} A100,100 0 ${largeArc},1 ${x2},${y2} Z`}
                          fill={seg.color}
                          stroke="white"
                          strokeWidth="1"
                        />
                        <text
                          x={tx}
                          y={ty}
                          textAnchor="middle"
                          dominantBaseline="middle"
                          fill="white"
                          fontSize="10"
                          fontWeight="bold"
                          transform={`rotate(${(i + 0.5) * segmentAngle}, ${tx}, ${ty})`}
                        >
                          {seg.label}
                        </text>
                      </g>
                    );
                  })}
                </svg>
              </div>
            </div>

            {/* Spin Button or Result */}
            {!result ? (
              <button
                onClick={handleSpin}
                disabled={spinning || hasSpun}
                className="w-full py-3 bg-yellow-400 text-indigo-900 font-bold rounded-xl hover:bg-yellow-300 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {hasSpun ? t('spin.alreadySpun', 'Bß║ín ─æ├ú quay rß╗ôi!') : spinning ? '≡ƒÄ░ ─Éang quay...' : t('spin.button', '≡ƒÄ» Quay ngay!')}
              </button>
            ) : (
              <div className="text-center">
                {result.code ? (
                  <>
                    <p className="text-lg font-bold text-yellow-400 mb-2">≡ƒÄë {result.label}!</p>
                    <div className="flex items-center justify-center gap-2 bg-white/10 rounded-xl px-4 py-3 mb-3">
                      <span className="font-mono font-bold text-lg tracking-wider">{result.code}</span>
                      <button onClick={handleCopy} className="p-1.5 bg-white/20 rounded-lg hover:bg-white/30">
                        {copied ? <Check size={16} /> : <Copy size={16} />}
                      </button>
                    </div>
                    <button onClick={onClose} className="text-sm text-white/60 hover:text-white">
                      {t('popup.continueShopping', 'Tiß║┐p tß╗Ñc mua sß║»m')}
                    </button>
                  </>
                ) : (
                  <>
                    <p className="text-white/80 mb-3">{t('spin.tryAgain', 'Ch├║c bß║ín may mß║»n lß║ºn sau!')}</p>
                    <button onClick={onClose} className="text-sm text-white/60 hover:text-white">
                      {t('common.close', '─É├│ng')}
                    </button>
                  </>
                )}
              </div>
            )}
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
};

import React from 'react';
import { cn } from '@/utils/cn';
import { useAuthStore } from '@/store';
import { getImageUrl } from '@/utils/format';

interface UserAvatarProps {
  className?: string;
  size?: 'xs' | 'sm' | 'md' | 'lg' | 'xl';
  avatarUrl?: string;
  fullName?: string;
  email?: string;
  showBorder?: boolean;
}

export const UserAvatar: React.FC<UserAvatarProps> = ({
  className,
  size = 'md',
  avatarUrl,
  fullName,
  email,
  showBorder = true
}) => {
  const { user } = useAuthStore();
  
  // Handle various property names from backend DTOs (avatar, Avatar, avatarUrl, AvatarUrl)
  const userAvatar = user?.avatar || (user as any)?.Avatar || (user as any)?.avatarUrl || (user as any)?.AvatarUrl;
  const currentAvatar = getImageUrl(avatarUrl || userAvatar);
  const currentName = fullName || user?.fullName;
  const currentEmail = email || user?.email;
  
  const sizeClasses = {
    xs: 'w-6 h-6 text-[10px]',
    sm: 'w-8 h-8 text-xs',
    md: 'w-10 h-10 text-sm',
    lg: 'w-16 h-16 text-2xl',
    xl: 'w-32 h-32 text-5xl',
  };

  const gradients = [
    'from-indigo-500 to-purple-500',
    'from-blue-500 to-cyan-500',
    'from-purple-500 to-pink-500',
    'from-emerald-500 to-teal-500',
    'from-orange-500 to-red-500'
  ];
  
  const initials = currentName?.charAt(0).toUpperCase() || currentEmail?.charAt(0).toUpperCase() || '?';
  const gradientIndex = initials.charCodeAt(0) % gradients.length;
  const gradient = gradients[gradientIndex];

  const [hasError, setHasError] = React.useState(false);

  // Reset error if avatar changes
  React.useEffect(() => {
    setHasError(false);
  }, [currentAvatar]);

  return (
    <div className={cn(
      "rounded-full overflow-hidden flex items-center justify-center relative shrink-0",
      showBorder && "border-2 border-white dark:border-slate-800 shadow-sm",
      sizeClasses[size],
      className
    )}>
      {(currentAvatar && !hasError) ? (
        <img 
          src={currentAvatar} 
          alt={initials} 
          className="w-full h-full object-cover"
          onError={() => {
            console.error('[UserAvatar] Failed to load image:', currentAvatar);
            setHasError(true);
          }}
        />
      ) : (
        <div className={cn(
          "w-full h-full flex items-center justify-center bg-gradient-to-br text-white font-bold shadow-inner",
          gradient
        )}>
