      );
      
      // When selected, it contains a Check icon.
      // <Check size={14} /> -> SVG
      // The parent button should have 'bg-indigo-600' class.
      
      const checkbox = document.querySelector('.absolute.top-3.left-3');
      expect(checkbox).toHaveClass('bg-indigo-600');
  });

});

