import React, { createContext, useContext, useState, PropsWithChildren } from 'react';
import { motion } from 'framer-motion';

// ============ Context ============
interface TabsContextType {
  value: string;
  onValueChange: (value: string) => void;
}

const TabsContext = createContext<TabsContextType | undefined>(undefined);

const useTabs = () => {
  const context = useContext(TabsContext);
  if (!context) {
    throw new Error('Tabs compound components must be used within a Tabs provider');
  }
  return context;
};

// ============ Components ============

interface TabsProps extends PropsWithChildren {
  value: string;
  onValueChange: (value: string) => void;
  className?: string;
}

const Tabs: React.FC<TabsProps> = ({ value, onValueChange, children, className = '' }) => {
  return (
    <TabsContext.Provider value={{ value, onValueChange }}>
      <div className={`w-full ${className}`}>
        {children}
      </div>
    </TabsContext.Provider>
  );
};

interface TabsListProps extends PropsWithChildren {
  className?: string;
}

const TabsList: React.FC<TabsListProps> = ({ children, className = '' }) => {
  return (
    <div className={`flex border-b mb-6 overflow-x-auto ${className}`}>
        {children}
    </div>
  );
};

interface TabsTriggerProps extends PropsWithChildren {
  value: string;
  className?: string;
}

const TabsTrigger: React.FC<TabsTriggerProps> = ({ value, children, className = '' }) => {
  const { value: selectedValue, onValueChange } = useTabs();
  const isSelected = selectedValue === value;

  return (
    <button
      onClick={() => onValueChange(value)}
      className={`relative px-6 py-3 font-medium whitespace-nowrap transition-colors outline-none
        ${isSelected ? 'text-primary' : 'text-secondary hover:text-primary'}
        ${className}
      `}
    >
      {children}
      {isSelected && (
        <motion.div
          layoutId="activeTabIndicator"
          className="absolute bottom-0 left-0 right-0 h-0.5 bg-primary"
          initial={false}
          transition={{ type: "spring", stiffness: 500, damping: 30 }}
        />
      )}
    </button>
  );
};

interface TabsContentProps extends PropsWithChildren {
  value: string;
  className?: string;
}

const TabsContent: React.FC<TabsContentProps> = ({ value, children, className = '' }) => {
  const { value: selectedValue } = useTabs();
  
  if (value !== selectedValue) return null;

  return (
    <motion.div
        initial={{ opacity: 0, y: 10 }}
        animate={{ opacity: 1, y: 0 }}
        exit={{ opacity: 0, y: -10 }}
        transition={{ duration: 0.2 }}
        className={className}
    >
      {children}
    </motion.div>
  );
};

// ============ Exports ============
const TabsCompound = Object.assign(Tabs, {
  List: TabsList,
  Trigger: TabsTrigger,
  Content: TabsContent,
});

export { TabsCompound as Tabs, TabsList, TabsTrigger, TabsContent };

import { useTranslation } from 'react-i18next';
import { Tag } from 'lucide-react';
import { DataTable, type DataTableColumn, CommonColumns } from '@/components/common';
import { type BrandDto } from '@/services/brandService';
import { getImageUrl } from '@/utils/format';
import { TableActions } from '@/components/ui';

interface BrandListProps {
    brands: BrandDto[];
    isLoading: boolean;
    pagination: {
        pageIndex: number;
        pageSize: number;
        totalItems: number;
        totalPages: number;
    };
    onPageChange: (page: number) => void;
    onPageSizeChange: (size: number) => void;
    onAdd: () => void;
    onEdit: (brand: BrandDto) => void;
    onDelete: (brand: BrandDto) => void;
    onBulkDelete: (items: BrandDto[]) => void;
    onView: (brand: BrandDto) => void;
    onRefresh: () => void;
    onImport: (file: File) => Promise<void>;
    onExport: () => Promise<any[]>;
    selectedIds: Set<string>;
    onSelectionChange: (ids: Set<string>) => void;
}

export const BrandList = ({
    brands,
    isLoading,
    pagination,
    onPageChange,
    onPageSizeChange,
    onAdd,
    onEdit,
    onDelete,
    onBulkDelete,
    onView,
    onRefresh,
    onImport,
    onExport,
    selectedIds,
    onSelectionChange
}: BrandListProps) => {
    const { t } = useTranslation();

    const columns: DataTableColumn<BrandDto>[] = [
        {
            id: 'logo',
            header: t('common.fields.image'),
            accessor: (brand) => brand.logoUrl ? (
                <img src={getImageUrl(brand.logoUrl)} alt={brand.name} className="w-10 h-10 object-contain rounded-md border border-gray-100" />
            ) : (
                <div className="w-10 h-10 rounded-md bg-gray-50 flex items-center justify-center text-gray-400">
                    <Tag size={20} />
                </div>
            ),
            className: 'w-[120px]'
        },
        {
            id: 'name',
            header: t('common.fields.name'),
            accessor: 'name',
            sortable: true,
        },
        {
            id: 'description',
            header: t('common.fields.description'),
            accessor: 'description',
            className: 'hidden md:table-cell max-w-[300px] truncate'
        },
        CommonColumns.createStatusColumn(t),
        {
            id: 'actions',
            header: '',
            className: 'w-[100px]',
            accessor: (brand) => (
                <TableActions
                    onView={() => onView(brand)}
                    onEdit={() => onEdit(brand)}
                    onDelete={() => onDelete(brand)}
                />
            )
        }
    ];

    return (
        <DataTable
            data={brands}
            columns={columns}
            isLoading={isLoading}
            searchPlaceholder={t('common.placeholders.search')}
            onAdd={onAdd}
            onRefresh={onRefresh}
            onImport={onImport}
            importTemplateUrl="/brands/template" // Assuming standard endpoint
            importTitle={t('common.importData')}
            onExportAllData={onExport}
            keyField="code"
            enableSelection
            selectedIds={selectedIds}
            onSelectionChange={onSelectionChange}
            onBulkDelete={(ids) => {
                const selectedBrands = brands.filter(b => ids.has(b.code));
                onBulkDelete(selectedBrands);
            }}

            // Server-side props
            currentPage={pagination.pageIndex}
            pageSize={pagination.pageSize}
            totalItems={pagination.totalItems}
            totalPages={pagination.totalPages}
            onPageChange={onPageChange}
            onPageSizeChange={onPageSizeChange}
        />
    );
};

import { useQuery, keepPreviousData } from '@tanstack/react-query';
import { brandService } from '@/services/brandService';
import { SearchCondition } from '@/services/baseService';

export const ADMIN_BRAND_KEYS = {
    all: ['admin', 'brands'] as const,
    list: (params: any) => [...ADMIN_BRAND_KEYS.all, 'list', params] as const,
    detail: (code: string) => [...ADMIN_BRAND_KEYS.all, 'detail', code] as const,
    stats: ['admin', 'brands', 'stats'] as const,
};

export function useAdminBrands(params: {
    pageIndex?: number;
    pageSize?: number;
    search?: string;
    isActive?: string;
}) {
    const filters: any[] = [];
    if (searchParams.isActive) filters.push({ field: 'IsActive', value: searchParams.isActive === 'true', operator: SearchCondition.Equal });
    if (searchParams.search) filters.push({ field: 'Name', value: searchParams.search, operator: SearchCondition.Contains });

    return useQuery({
        queryKey: ADMIN_BRAND_KEYS.list(params),
        queryFn: async () => {
            const response = await brandService.search({
                pageIndex: params.pageIndex,
                pageSize: params.pageSize,
                filters: filters.length > 0 ? filters : undefined,
            });

            if (!response.success) {
                throw new Error(response.message || 'Failed to fetch brands');
            }

            return {
                items: response.data?.items || [],
                totalItems: response.data?.totalItems || 0,
                totalPages: Math.ceil((response.data?.totalItems || 0) / (params.pageSize || 10)),
                pageIndex: params.pageIndex || 1,
                pageSize: params.pageSize || 10
            };
        },
        placeholderData: keepPreviousData,
        staleTime: 1000 * 60,
    });
}
// Note: brandService doesn't have a getStats endpoint yet, we'll use local stats or empty
export function useBrandStats() {
    return { data: null, isLoading: false };
}

import { z } from 'zod';
import { useTranslation } from 'react-i18next';
import { BaseForm, FieldDefinition } from '@/components/common';
import { useCategories } from '@/hooks';
import { contentWeaverService } from '@/services/ContentWeaverService';
import { Sparkles } from 'lucide-react';
import { Button } from '@/components/ui';

// ============ Schema ============
const categorySchema = z.object({
  name: z.string().min(1, 'required'), // will be localized in component or handling
  description: z.string().optional(),
  parentCode: z.string().optional(),
  imageURL: z.string().optional(),
  isActive: z.boolean(),
});

export type CategoryFormData = z.infer<typeof categorySchema>;

// ============ Props ============
interface CategoryFormProps {
  initialData?: Partial<CategoryFormData>;
  onSubmit: (data: CategoryFormData) => void | Promise<void>;
  onCancel: () => void;
  isLoading?: boolean;
  isModal?: boolean;
  modalOpen?: boolean;
  modalTitle?: string;
  excludeCode?: string;
  imageBaseUrl?: string;
}

// ============ Component ============
export const CategoryForm = ({
  initialData,
  onSubmit,
  onCancel,
  isLoading = false,
  isModal = true,
  modalOpen = false,
  modalTitle,
  excludeCode,
  imageBaseUrl,
}: CategoryFormProps) => {
  const { t } = useTranslation();
  const { data: categories = [] } = useCategories();

  // Build parent category options
  const parentOptions = [
    { value: '', label: t('common.actions.none') },
    ...categories
      .filter((c: any) => c.code !== excludeCode) // Exclude self by code
      .map((c: any) => ({ value: c.code, label: c.name })),
  ];

  // Field definitions
  const fields: FieldDefinition[] = [
    {
      name: 'imageURL',
      type: 'image',
      label: t('common.fields.image'),
      colSpan: 12,
    },
    {
      name: 'name',
      type: 'text',
      label: t('common.fields.name'),
      placeholder: t('common.placeholders.enterName'),
      required: true,
      colSpan: 12,
    },
    {
      name: 'description',
      type: 'textarea',
      label: t('common.fields.description'),
      placeholder: t('common.placeholders.enterDescription'),
      rows: 3,
      colSpan: 12,
    },
    {
      name: 'parentCode',
      type: 'select',
      label: t('common.fields.parentCategory'),
      options: parentOptions,
      colSpan: 12,
    },
    {
      name: 'isActive',
      type: 'switch',
      label: t('common.fields.status'),
      description: t('admin.statusHint'),
      colSpan: 12,
    },
  ];

  // Default values
  const defaultValues: CategoryFormData = {
    name: initialData?.name || '',
    description: initialData?.description || '',
    parentCode: initialData?.parentCode || '',
    imageURL: initialData?.imageURL || '',
    isActive: initialData?.isActive ?? true,
  };

  return (
    <BaseForm<CategoryFormData>
      schema={categorySchema}
      defaultValues={defaultValues}
      fields={fields}
      onSubmit={onSubmit}
      onCancel={onCancel}
      isLoading={isLoading}
      submitLabel={initialData?.name ? t('common.update') : t('common.create')}
      isModal={isModal}
      modalOpen={modalOpen}
      modalTitle={modalTitle || (initialData?.name ? t('admin.actions.edit') : t('admin.actions.create'))}
      onModalClose={onCancel}
      imageBaseUrl={imageBaseUrl || ''}
      renderBefore={(form) => (
        <div className="mb-4 p-4 bg-accent/5 border border-accent/20 rounded-2xl flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-accent/10 rounded-xl text-accent">
              <Sparkles size={20} />
            </div>
            <div>
              <p className="text-sm font-bold text-text-primary">Autonomous Weaver</p>
              <p className="text-xs text-text-secondary">Generate recursive localized descriptions.</p>
            </div>
          </div>
          <Button
            type="button"
            variant="outline"
            size="sm"
            onClick={() => {
              const name = form.getValues('name');
              const generated = contentWeaverService.generateDescription(name || 'Danh mß╗Ñc', 'default');
              form.setValue('description', generated);
            }}
            disabled={!form.watch('name')}
            leftIcon={<Sparkles size={14} />}
            className="neon-border-sm"
          >
            Auto-generate
          </Button>
        </div>
      )}
    />
  );
};

export default CategoryForm;

