import React, { useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import { useForm } from 'react-hook-form';
import { Shield, Info, Menu as MenuIcon } from 'lucide-react';
import { Button, Input, Textarea, Badge, Loading } from '@/components/ui';
import { usePermissions, useMenus } from '@/hooks';
import { Menu, Permission } from '@/types';

export interface RoleFormData {
    name: string;
    description?: string;
    isActive: boolean;
    permissionCodes: string[];
    menuCodes: string[];
}

interface RoleFormProps {
    initialData?: RoleFormData;
    onSubmit: (data: RoleFormData) => Promise<void>;
    onCancel: () => void;
    isLoading?: boolean;
    isEdit?: boolean;
}

export const RoleForm: React.FC<RoleFormProps> = ({
    initialData,
    onSubmit,
    onCancel,
    isLoading,
    isEdit
}) => {
    const { t } = useTranslation();
    const { register, handleSubmit, formState: { errors }, setValue, watch, reset } = useForm<RoleFormData>({
        defaultValues: initialData || {
            name: '',
            description: '',
            isActive: true,
            permissionCodes: [],
            menuCodes: []
        }
    });

    React.useEffect(() => {
        if (initialData) {
            reset(initialData);
        } else {
            reset({
                name: '',
                description: '',
                isActive: true,
                permissionCodes: [],
                menuCodes: []
            });
        }
    }, [initialData, reset]);

    const selectedPermissionCodes = watch('permissionCodes');
    const selectedMenuCodes = watch('menuCodes');
    
    // Fetch all permissions
    const { data: permissionsResult, isLoading: isPermissionsLoading } = usePermissions();
    const permissions = permissionsResult?.data || [];

    // Fetch all menus
    const { data: menusResult, isLoading: isMenusLoading } = useMenus();
    const menus = menusResult?.data || [];

    // Group permissions by module
    const groupedPermissions = permissions.reduce((acc, curr) => {
        if (!acc[curr.module]) acc[curr.module] = [];
        acc[curr.module].push(curr);
        return acc;
    }, {} as Record<string, Permission[]>);

    // Group menus by groupName
    const groupedMenus = menus.reduce((acc, curr) => {
        if (!acc[curr.groupName]) acc[curr.groupName] = [];
        acc[curr.groupName].push(curr);
        return acc;
    }, {} as Record<string, Menu[]>);

    const togglePermission = useCallback((code: string) => {
        const current = [...selectedPermissionCodes];
        const index = current.indexOf(code);
        if (index > -1) {
            current.splice(index, 1);
        } else {
            current.push(code);
        }
        setValue('permissionCodes', current);
    }, [selectedPermissionCodes, setValue]);

    const toggleMenu = useCallback((code: string) => {
        const current = [...selectedMenuCodes];
        const index = current.indexOf(code);
        if (index > -1) {
            current.splice(index, 1);
        } else {
            current.push(code);
        }
        setValue('menuCodes', current);
    }, [selectedMenuCodes, setValue]);

    const togglePermissionModule = useCallback((module: string) => {
        const modulePerms = groupedPermissions[module].map(p => p.code);
        const allSelected = modulePerms.every(code => selectedPermissionCodes.includes(code));
        
        let newSelection = [...selectedPermissionCodes];
        if (allSelected) {
            newSelection = newSelection.filter(code => !modulePerms.includes(code));
        } else {
            modulePerms.forEach(code => {
                if (!newSelection.includes(code)) newSelection.push(code);
            });
        }
        setValue('permissionCodes', newSelection);
    }, [groupedPermissions, selectedPermissionCodes, setValue]);

    const toggleMenuGroup = useCallback((groupName: string) => {
        const groupMenus = groupedMenus[groupName].map(m => m.code);
        const allSelected = groupMenus.every(code => selectedMenuCodes.includes(code));
        
        let newSelection = [...selectedMenuCodes];
        if (allSelected) {
            newSelection = newSelection.filter(code => !groupMenus.includes(code));
        } else {
            groupMenus.forEach(code => {
                if (!newSelection.includes(code)) newSelection.push(code);
            });
        }
        setValue('menuCodes', newSelection);
    }, [groupedMenus, selectedMenuCodes, setValue]);

    const isModuleAllSelected = useCallback((module: string) => {
        return groupedPermissions[module]?.every(p => selectedPermissionCodes.includes(p.code)) ?? false;
    }, [groupedPermissions, selectedPermissionCodes]);

    const isModuleAnySelected = useCallback((module: string) => {
        return groupedPermissions[module]?.some(p => selectedPermissionCodes.includes(p.code)) ?? false;
    }, [groupedPermissions, selectedPermissionCodes]);

    const isMenuGroupAllSelected = useCallback((groupName: string) => {
        return groupedMenus[groupName]?.every(m => selectedMenuCodes.includes(m.code)) ?? false;
    }, [groupedMenus, selectedMenuCodes]);

    const isMenuGroupAnySelected = useCallback((groupName: string) => {
        return groupedMenus[groupName]?.some(m => selectedMenuCodes.includes(m.code)) ?? false;
    }, [groupedMenus, selectedMenuCodes]);

    return (
        <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
            {/* General Info */}
            <div className="space-y-4">
                <h3 className="text-lg font-semibold flex items-center gap-2 border-b pb-2">
                    <Info size={18} />
                    {t('common.fields.info')}
                </h3>
                
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <Input
                        label={t('common.fields.name')}
                        {...register('name', { required: t('validation.required') })}
                        error={errors.name?.message || ''}
                        placeholder={t('rbac.roles.namePlaceholder')}
                    />

                    <div className="flex items-center gap-2 pt-6">
                        <input
                            type="checkbox"
                            id="isActive"
                            {...register('isActive')}
                            className="w-4 h-4 text-indigo-600 border-gray-300 rounded focus:ring-indigo-500"
                        />
                        <label htmlFor="isActive" className="text-sm font-medium text-gray-700 dark:text-gray-300">
                            {t('common.fields.active')}
                        </label>
                    </div>
                </div>

                <Textarea
                    label={t('common.fields.description')}
                    {...register('description')}
                    placeholder={t('rbac.roles.descriptionPlaceholder')}
                    rows={2}
                />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                {/* Menu Access */}
                <div className="space-y-4">
                    <h3 className="text-lg font-semibold flex items-center gap-2 border-b pb-2">
                        <MenuIcon size={18} />
                        {t('rbac.menuAccess')}
                        <Badge size="sm" color="primary" className="ml-auto">
                            {selectedMenuCodes.length} {t('common.selected')}
                        </Badge>
                    </h3>

                    {isMenusLoading ? (
                        <div className="flex justify-center py-8">
                            <Loading />
                        </div>
                    ) : (
                        <div className="max-h-[300px] overflow-y-auto pr-2 space-y-3">
                            {Object.entries(groupedMenus).map(([groupName, menuItems]) => (
                                <div key={groupName} className="border rounded-lg p-3 bg-slate-50 dark:bg-slate-800/50">
                                    <div className="flex items-center justify-between mb-2">
                                        <div className="flex items-center gap-2">
                                            <input
                                                type="checkbox"
                                                checked={isMenuGroupAllSelected(groupName)}
                                                onChange={() => toggleMenuGroup(groupName)}
                                                className="w-4 h-4 text-indigo-600 border-gray-300 rounded focus:ring-indigo-500"
                                            />
                                            <span className="font-bold text-slate-800 dark:text-slate-200">{groupName}</span>
                                        </div>
                                        <Badge size="sm" variant="soft" color={isMenuGroupAllSelected(groupName) ? 'success' : isMenuGroupAnySelected(groupName) ? 'info' : 'secondary'}>
                                            {menuItems.filter(m => selectedMenuCodes.includes(m.code)).length} / {menuItems.length}
                                        </Badge>
                                    </div>
                                    <div className="grid grid-cols-1 gap-1 pl-6">
                                        {menuItems.map(menu => (
                                            <label key={menu.code} className="flex items-center gap-2 py-1 cursor-pointer hover:bg-slate-100 dark:hover:bg-slate-700/50 rounded px-1 group">
                                                <input
                                                    type="checkbox"
                                                    checked={selectedMenuCodes.includes(menu.code)}
                                                    onChange={() => toggleMenu(menu.code)}
                                                    className="w-3.5 h-3.5 text-indigo-600 border-gray-300 rounded focus:ring-indigo-500"
                                                />
                                                <span className="text-sm text-slate-600 dark:text-slate-400 group-hover:text-slate-900 dark:group-hover:text-slate-200">
                                                    {menu.name}
                                                </span>
                                            </label>
                                        ))}
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>

                {/* Permissions */}
                <div className="space-y-4">
                    <h3 className="text-lg font-semibold flex items-center gap-2 border-b pb-2">
                        <Shield size={18} />
                        {t('rbac.permissions')}
                        <Badge size="sm" color="primary" className="ml-auto">
                            {selectedPermissionCodes.length} {t('common.selected')}
                        </Badge>
                    </h3>

                    {isPermissionsLoading ? (
                        <div className="flex justify-center py-8">
                            <Loading />
                        </div>
                    ) : (
                        <div className="max-h-[300px] overflow-y-auto pr-2 space-y-3">
                            {Object.entries(groupedPermissions).map(([module, perms]) => (
                                <div key={module} className="border rounded-lg p-3 bg-slate-50 dark:bg-slate-800/50">
                                    <div className="flex items-center justify-between mb-2">
                                        <div className="flex items-center gap-2">
                                            <input
                                                type="checkbox"
                                                checked={isModuleAllSelected(module)}
                                                onChange={() => togglePermissionModule(module)}
                                                className="w-4 h-4 text-indigo-600 border-gray-300 rounded focus:ring-indigo-500"
                                            />
                                            <span className="font-bold text-slate-800 dark:text-slate-200">{module}</span>
                                        </div>
                                        <Badge size="sm" variant="soft" color={isModuleAllSelected(module) ? 'success' : isModuleAnySelected(module) ? 'info' : 'secondary'}>
                                            {perms.filter(p => selectedPermissionCodes.includes(p.code)).length} / {perms.length}
                                        </Badge>
                                    </div>
                                    <div className="grid grid-cols-1 gap-1 pl-6">
                                        {perms.map(p => (
                                            <label key={p.code} className="flex items-center gap-2 py-1 cursor-pointer hover:bg-slate-100 dark:hover:bg-slate-700/50 rounded px-1 group">
                                                <input
                                                    type="checkbox"
                                                    checked={selectedPermissionCodes.includes(p.code)}
                                                    onChange={() => togglePermission(p.code)}
                                                    className="w-3.5 h-3.5 text-indigo-600 border-gray-300 rounded focus:ring-indigo-500"
                                                />
                                                <span className="text-sm text-slate-600 dark:text-slate-400 group-hover:text-slate-900 dark:group-hover:text-slate-200">
                                                    {p.name}
                                                </span>
                                            </label>
                                        ))}
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>

            <div className="flex justify-end gap-3 pt-6 border-t">
                <Button type="button" variant="ghost" onClick={onCancel} disabled={isLoading}>
                    {t('common.actions.cancel')}
                </Button>
                <Button type="submit" isLoading={!!isLoading}>
                    {isEdit ? t('common.actions.save') : t('common.actions.create')}
                </Button>
            </div>
        </form>
    );
};

import { useState, useEffect } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { Mail, Lock, Eye, EyeOff, ArrowRight } from 'lucide-react';
import { Button, Input } from '@/components/ui';
import { useAuthStore, useToast } from '@/store';
import { UserRole, UserStatus } from '@/types';
import { authService } from '@/services/authService';
import { AuthLayout } from '@/layouts/AuthLayout';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { createSchemas } from '@/utils/schemas';
import { signInWithPopup, type AuthProvider } from 'firebase/auth';
import { auth, googleProvider, facebookProvider } from '@/config/firebase';

export const LoginPage = () => {
  const { t } = useTranslation();
  const { loginSchema } = createSchemas(t);
  
  interface LoginFormData {
    email: string;
    password: string;
    remember: boolean;
  }

  const navigate = useNavigate();
  const location = useLocation();
  const { login, isAuthenticated, user } = useAuthStore();
  const toast = useToast();
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const {
      register,
      handleSubmit,
      setValue,
      formState: { errors },
  } = useForm<LoginFormData>({
      resolver: zodResolver(loginSchema),
      defaultValues: {
          email: '',
          password: '',
          remember: false,
      }
  });

  // Redirect if already authenticated
  useEffect(() => {
    if (isAuthenticated && user) {
        if (String(user.role).toLowerCase() === 'admin') { 
            navigate('/admin', { replace: true });
        } else {
            navigate('/', { replace: true });
        }
    }
  }, [isAuthenticated, user, navigate]);

  /* Load saved email if 'Remember Me' was checked */
  useEffect(() => {
      try {
          const isRemember = localStorage.getItem('vnvt-remember') === 'true';
          if (isRemember) {
              const savedEmail = localStorage.getItem('vnvt-email');
              if (savedEmail) {
                  setValue('email', savedEmail);
                  setValue('remember', true);
              }
          }
      } catch (e) {
          console.warn('LocalStorage access denied', e);
      }
  }, [setValue]);

  const from = (location.state as { from?: string })?.from || '/';

  const onSubmit = async (data: LoginFormData) => {
    setIsLoading(true);
    setError(null);

    try {
      const response = await authService.login({
        username: data.email,
        password: data.password,
      });

      if (response.success && response.data) {
        const { token, refreshToken, user } = response.data;

        // Handle Remember Me preference
        try {
            if (data.remember) {
                localStorage.setItem('vnvt-remember', 'true');
                localStorage.setItem('vnvt-email', data.email);
            } else {
                localStorage.removeItem('vnvt-remember');
                localStorage.removeItem('vnvt-email');
            }
        } catch (e) {
            console.warn('LocalStorage access denied', e);
        }

        login(
          {
            code: user.code,
            email: user.email,
            fullName: user.fullName || user.username,
            role: (user.role as UserRole) || UserRole.Customer,
            status: UserStatus.Active,
            createdAt: new Date().toISOString(),
            avatar: user.avatar || (user as any).Avatar, // Handle PascalCase from backend
            permissions: user.permissions,
            menus: user.menus
          },
          token,
          refreshToken,
          user.menus
        );

        toast.success(t('messages.loginSuccess'));
        
        // Redirect to admin if admin role, otherwise to original destination
        // backend returns PascalCase 'Admin', Enum is 'Admin'
        if (String(user.role).toLowerCase() === 'admin') { 
            navigate('/admin', { replace: true });
        } else {
            navigate(from, { replace: true });
        }
      } else {
        setError(response.message || 'T├¬n ─æ─âng nhß║¡p hoß║╖c mß║¡t khß║⌐u kh├┤ng ─æ├║ng');
      }
    } catch (err) {
      toast.error(t('messages.error'));
      setError('C├│ lß╗ùi xß║úy ra. Vui l├▓ng thß╗¡ lß║íi.');
      console.error('Login error:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSocialLogin = async (provider: string, authProvider: AuthProvider) => {
    setIsLoading(true);
    setError(null);
    try {
      const result = await signInWithPopup(auth, authProvider);
      const token = await result.user.getIdToken();
      
      const response = await authService.externalLogin(provider, token);
      
      if (response.success && response.data) {
        const { token: accessToken, refreshToken, user: userData } = response.data;
        
        login(
          {
            code: userData.code,
            email: userData.email,
            fullName: userData.fullName || userData.username,
            role: (userData.role as UserRole) || UserRole.Customer,
            status: UserStatus.Active,
            createdAt: new Date().toISOString(),
            avatar: userData.avatar || (userData as any).Avatar,
            permissions: userData.permissions,
            menus: userData.menus
          },
          accessToken,
          refreshToken,
          userData.menus
        );

        toast.success(t('messages.loginSuccess'));
        
        if (String(userData.role).toLowerCase() === 'admin') { 
            navigate('/admin', { replace: true });
        } else {
            navigate(from, { replace: true });
        }
      } else {
        setError(response.message || t('messages.error'));
      }
    } catch (err: unknown) {
      console.error(`${provider} login error:`, err);
      const firebaseError = err as { code?: string };
      const isPopupClosed = firebaseError.code === 'auth/popup-closed-by-user';
      if (!isPopupClosed) {
        toast.error(t('messages.error'));
        setError(t('messages.error'));
      }
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <AuthLayout title={t('login.title')} subtitle={t('login.subtitle')}>
      <div className="grid grid-cols-2 gap-4 mb-6">
        {/* Google Login */}
        <button 
          onClick={() => handleSocialLogin('google', googleProvider)}
          disabled={isLoading}
          className="flex items-center justify-center gap-2 py-3 px-4 border rounded-xl font-medium hover:bg-gray-50 transition-colors disabled:opacity-50"
        >
          <img src="https://www.gstatic.com/firebasejs/ui/2.0.0/images/auth/google.svg" alt="Google" className="w-5 h-5" />
          <span>Google</span>
        </button>

        {/* Facebook Login */}
        <button 
          onClick={() => handleSocialLogin('facebook', facebookProvider)}
          disabled={isLoading}
          className="flex items-center justify-center gap-2 py-3 px-4 border rounded-xl font-medium hover:bg-gray-50 transition-colors disabled:opacity-50"
        >
          <img src="https://www.gstatic.com/firebasejs/ui/2.0.0/images/auth/facebook.svg" alt="Facebook" className="w-5 h-5" />
          <span>Facebook</span>
        </button>
      </div>

      <div className="flex items-center gap-4 mb-6">
        <hr className="flex-1" />
        <span className="text-tertiary text-sm">{t('login.or')}</span>
        <hr className="flex-1" />
      </div>

      {/* Form */}
      <form onSubmit={handleSubmit(onSubmit)} className="space-y-4" noValidate>
        {error && (
          <div className="p-3 border border-error bg-error/10 text-error text-sm rounded-lg">
            {error}
          </div>
        )}
        <Input
          label="Email"
          type="email"
          placeholder="email@example.com"
          {...register('email')}
          data-testid="email-input"
          leftIcon={<Mail size={18} />}
          required
          {...(errors.email?.message ? { error: errors.email.message } : {})}
        />

        <Input
          label={t('login.password')}
          type={showPassword ? 'text' : 'password'}
          placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
          {...register('password')}
          data-testid="password-input"
          leftIcon={<Lock size={18} />}
          rightIcon={
            <button
              type="button"
              onClick={() => setShowPassword(!showPassword)}
              className="flex items-center justify-center p-1 text-slate-400 opacity-50 hover:opacity-100 hover:text-primary focus:outline-none transition-all"
              tabIndex={-1}
            >
              {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
            </button>
          }
          required
          {...(errors.password?.message ? { error: errors.password.message } : {})}
        />

        <div className="flex items-center justify-between">
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="checkbox"
              {...register('remember')}
              className="w-4 h-4 rounded"
            />
            <span className="text-sm text-secondary">{t('login.remember')}</span>
          </label>
          <Link to="/forgot-password" className="text-sm text-primary hover:underline">
            {t('login.forgot')}
          </Link>
        </div>

        <Button
          type="submit"
          fullWidth
          size="lg"
          data-testid="login-button"
          isLoading={isLoading} 
          rightIcon={<ArrowRight size={20} />}
        >
          {t('login.submit')}
        </Button>
      </form>

      {/* Register Link */}
      <p className="text-center mt-6 text-secondary">
        {t('login.noAccount')}{' '}
        <Link to="/register" className="text-primary font-semibold hover:underline">
          {t('login.register')}
        </Link>
      </p>
    </AuthLayout>
  );
};

export default LoginPage;

