const BackToTop = () => {
    const [isVisible, setIsVisible] = useState(false);
    const [progress, setProgress] = useState(0);

    useEffect(() => {
        const toggleVisibility = () => {
            const scrolled = window.scrollY;
            const threshold = 300;
            setIsVisible(scrolled > threshold);

            const height = document.documentElement.scrollHeight - window.innerHeight;
            if (height > 0) {
                setProgress((scrolled / height) * 100);
            }
        };

        window.addEventListener('scroll', toggleVisibility);
        return () => window.removeEventListener('scroll', toggleVisibility);
    }, []);

    const scrollToTop = () => {
        window.scrollTo({
            top: 0,
            behavior: 'smooth',
        });
    };

    return (
        <AnimatePresence>
            {isVisible && (
                <motion.button
                    initial={{ opacity: 0, scale: 0.5 }}
                    animate={{ opacity: 1, scale: 1 }}
                    exit={{ opacity: 0, scale: 0.5 }}
                    onClick={scrollToTop}
                    className="fixed bottom-8 right-8 z-50 p-0 w-12 h-12 bg-white rounded-full shadow-lg border border-gray-100 flex items-center justify-center group"
                >
                    <svg className="w-12 h-12 -rotate-90">
                        <circle
                            cx="24"
                            cy="24"
                            r="20"
                            stroke="currentColor"
                            strokeWidth="2.5"
                            fill="transparent"
                            className="text-gray-100"
                        />
                        <circle
                            cx="24"
                            cy="24"
                            r="20"
                            stroke="currentColor"
                            strokeWidth="2.5"
                            fill="transparent"
                            strokeDasharray={125.6}
                            strokeDashoffset={125.6 - (progress / 100) * 125.6}
                            className="text-indigo-600 transition-all duration-300"
                        />
                    </svg>
                    <div className="absolute inset-0 flex items-center justify-center text-secondary group-hover:text-indigo-600 transition-colors">
                        <ArrowUp size={20} />
                    </div>
                </motion.button>
            )}
        </AnimatePresence>
    );
};

