import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { userService } from '@/services/userService';
import { useToast, useAuthStore, useToastStore } from '@/store';
import { Loading } from '@/components/ui';
import { ProfileForm, AccountSecurity, NotificationSettings, LoyaltySummary } from './components';
import { type UpdateProfileData } from './components/ProfileForm';

const ProfileContent = () => {
    const { t } = useTranslation();
    const toast = useToast();
    const { user, updateUser } = useAuthStore();
    const [loading, setLoading] = useState(false);
    const [pageLoading, setPageLoading] = useState(true);
    const [initialData, setInitialData] = useState({
        fullName: '',
        email: '',
        phone: '',
        avatar: ''
    });

    useEffect(() => {
        const fetchProfile = async () => {
            try {
                const res = await userService.getProfile();
                if(res.success && res.data) {
                    const avatarVal = res.data.avatar || (res.data as any).Avatar;
                    const data = {
                        fullName: res.data.fullName || '',
                        email: res.data.email || '',
                        phone: res.data.phone || '',
                        avatar: avatarVal || ''
                    };
                    setInitialData(data);
                    // Update auth store with normalized avatar
                    updateUser({
                        ...res.data,
                        avatar: avatarVal
                    } as any);
                }
            } catch (error) {
                console.error('Error fetching profile:', error);
            } finally {
                setPageLoading(false);
            }
        };

        fetchProfile();
    }, []); 

    const handleSaveProfile = async (data: UpdateProfileData) => {
        setLoading(true);
        try {
            const res = await userService.updateProfile({
                fullName: data.fullName,
                phone: data.phone,
                email: data.email,
                avatarUrl: data.avatarUrl
            });

            if (res.success && res.data) {
                toast.success(t('common.messages.updateSuccess'));
                
                // Normalize avatar field before updating store
                const avatarVal = res.data.avatar || (res.data as any).Avatar;
                updateUser({
                    ...res.data,
                    avatar: avatarVal
                } as any);

                setInitialData({
                    fullName: res.data.fullName || '',
                    email: res.data.email || '',
                    phone: res.data.phone || '',
                    avatar: avatarVal || ''
                });
            } else {
                toast.error(res.message || t('common.messages.updateError'));
            }
        } catch (error) {
            console.error('Error saving profile:', error);
            toast.error(t('common.messages.updateError'));
        } finally {
            setLoading(false);
        }
    };

    const handlePasswordChange = () => {
        toast.info(t('common.messages.featureComingSoon'));
    };

    const handleTwoFactorSetup = () => {
        toast.info(t('common.messages.featureComingSoon'));
    };

    const handleDeleteAccount = async () => {
        if (!window.confirm(t('profile.deleteAccount.confirm', 'Bß║ín c├│ chß║»c chß║»n muß╗æn x├│a t├ái khoß║ún? H├ánh ─æß╗Öng n├áy kh├┤ng thß╗â ho├án t├íc.'))) return;
        
        try {
            const res = await userService.deleteAccount();
            if (res.success) {
                toast.success(t('profile.deleteAccount.success', 'T├ái khoß║ún ─æ├ú ─æ╞░ß╗úc v├┤ hiß╗çu h├│a.'));
                // Logout user
                useAuthStore.getState().logout();
                window.location.href = '/';
            } else {
                toast.error(res.message || t('profile.deleteAccount.error', 'C├│ lß╗ùi xß║úy ra khi x├│a t├ái khoß║ún.'));
            }
        } catch (error) {
            console.error('Error deleting account:', error);
            toast.error(t('profile.deleteAccount.error', 'C├│ lß╗ùi xß║úy ra khi x├│a t├ái khoß║ún.'));
        }
    };

    if (pageLoading) return <div className="flex justify-center py-20"><Loading /></div>;

    return (
        <div className="space-y-8 animate-fade-in pb-10">
            {/* Loyalty & Credit Summary */}
            {user && user.role === 'Customer' && (
                <LoyaltySummary 
                    points={user.loyaltyPoints || 0}
                    debtLimit={user.debtLimit || 0}
                    currentDebt={user.currentDebt || 0}
