                    <p className="text-sm text-rose-500 mb-4">
                        {t('profile.dangerZone.description', 'X├│a t├ái khoß║ún cß╗ºa bß║ín sß║╜ v├┤ hiß╗çu h├│a quyß╗ün truy cß║¡p. H├ánh ─æß╗Öng n├áy c├│ thß╗â ─æ╞░ß╗úc kh├┤i phß╗Ñc bß╗ƒi quß║ún trß╗ï vi├¬n.')}
                    </p>
                    <button
                        onClick={handleDeleteAccount}
                        className="px-6 py-2 bg-rose-600 text-white rounded-xl font-semibold hover:bg-rose-700 transition-colors shadow-lg shadow-rose-200"
                    >
                        {t('profile.dangerZone.deleteButton', 'X├│a t├ái khoß║ún')}
                    </button>
                </div>
            </div>
        </div>
    );
};

