import { useToast } from '@/store';
import { formatCurrency } from '@/utils/format';
import { ProductLogistics } from './ProductLogistics';
import { useBuyNow } from '@/features/checkout/hooks/useBuyNow';
import type { Product } from '@/types';

const PriceHistoryChart = React.lazy(() => import('@/features/product/components/PriceHistoryChart'));

interface ProductInfoProps {
  product: Product;
  hasFixedPrice: boolean;
  stockStatus: { label: string; color: BadgeColor; text: string } | null;
  quantity: number;
  setQuantity: (q: number) => void;
  handleAddToCart: () => void;
  handleBuyNow: () => void;
  isAddingToCart: boolean;
  isWishlisted: boolean;
  handleWishlistToggle: () => void;
  isCompared: boolean;
  handleCompareToggle: () => void;
}

export const ProductInfo: React.FC<ProductInfoProps> = ({
  product,
  hasFixedPrice,
  stockStatus,
  quantity,
  setQuantity,
  handleAddToCart,
  handleBuyNow,
  isAddingToCart,
  isWishlisted,
  handleWishlistToggle,
  isCompared,
  handleCompareToggle,
}) => {
  const { t } = useTranslation();
  const { success } = useToast();
  const { handleBuyNow: triggerBuyNow } = useBuyNow();

  // Override handleBuyNow from props if needed, or just use the hook directly
  const onBuyNowClick = () => {
    triggerBuyNow(product, quantity);
  };

  // Stars renderer
  const renderStars = useMemo(() => {
    if (!product) return null;
    const ratingValue = product.averageRating ?? product.rating ?? 0;
    return Array.from({ length: 5 }).map((_, i) => (
      <Star
        key={i}
        size={18}
        className={i < Math.floor(ratingValue) ? 'fill-yellow-400 text-yellow-400' : 'text-gray-300'}
      />
    ));
  }, [product]);

  return (
    <div className="space-y-6 lg:col-span-3">
