                </div>
                <div className="flex justify-between text-[10px] text-slate-400 font-bold uppercase">
                  <span>{t('product.itemsSold', '─É├ú b├ín: 15')}</span>
                  <span>{t('product.itemsRemaining', 'C├▓n lß║íi: 5')}</span>
                </div>
              </div>
            )}

            {product.wholesalePrice && (
              <div className="flex items-center gap-2 text-sm text-secondary pt-2 border-t border-slate-100 dark:border-slate-700">
                <Badge color="secondary" className="font-semibold uppercase tracking-tighter">{t('product.wholesalePrice', 'Gi├í sß╗ë')}</Badge>
                <span className="font-bold text-slate-900 dark:text-white">{formatCurrency(product.wholesalePrice)}</span>
                <span className="text-[11px] opacity-70">({t('product.contactForBestPrice', 'Li├¬n hß╗ç ─æß╗â nhß║¡n ╞░u ─æ├úi tß╗æt nhß║Ñt')})</span>
              </div>
            )}

            {/* Stock Urgency Alert */}
            {(product.stockQuantity ?? product.stock) > 0 && (product.stockQuantity ?? product.stock) <= 10 && (
              <motion.div 
                initial={{ opacity: 0, x: -10 }}
                animate={{ opacity: 1, x: 0 }}
                className="flex items-center gap-2 text-rose-600 bg-rose-50 dark:bg-rose-900/20 px-3 py-2 rounded-lg border border-rose-100 dark:border-rose-900/30 text-xs font-bold"
              >
                <div className="w-2 h-2 rounded-full bg-rose-600 animate-pulse" />
                {t('product.lowStockAlert', 'Chß╗ë c├▓n {{count}} sß║ún phß║⌐m trong kho - ─Éß║╖t ngay!', { count: product.stockQuantity ?? product.stock })}
              </motion.div>
            )}
          </div>
        ) : (
          <div className="flex items-center gap-3 py-2">
            <Phone className="text-indigo-600" />
            <span className="text-2xl font-bold text-slate-900 dark:text-white">{t('product.contactForPrice')}</span>
          </div>
        )}
      </div>

      {/* Core Info Details */}
      <div className="grid grid-cols-2 gap-y-2 text-sm">
        <div className="text-tertiary">{t('product.code', 'M├ú sß║ún phß║⌐m')}:</div>
        <div className="text-primary font-medium">{product.code}</div>
        
        <div className="text-tertiary">{t('product.unit', '─É╞ín vß╗ï t├¡nh')}:</div>
        <div className="text-primary">{product.baseUnit || t('product.defaultUnit', 'C├íi')}</div>
        
        <div className="text-tertiary">{t('product.binLocation', 'Vß╗ï tr├¡ kho')}:</div>
        <div className="text-primary">{product.binLocation || t('common.updating', '─Éang cß║¡p nhß║¡t')}</div>
      </div>

      {/* Description */}
      <p className="text-secondary leading-relaxed line-clamp-3">{product.description}</p>

      {/* Product Logistics */}
      <ProductLogistics product={product} />

      {/* Quantity & Add to Cart */}
      {hasFixedPrice && (
        <div className="flex flex-col sm:flex-row gap-4">
          {/* Quantity */}
          <div className="flex items-center border rounded-lg bg-white">
            <button
              onClick={() => setQuantity(Math.max(1, quantity - 1))}
              className="p-3 hover:bg-hover transition-colors"
            >
              <Minus size={18} />
            </button>
            <span className="w-16 text-center font-semibold">{quantity}</span>
            <button
              onClick={() => setQuantity(Math.min(product.stockQuantity ?? product.stock, quantity + 1))}
              disabled={quantity >= (product.stockQuantity ?? product.stock)}
              className={`p-3 transition-colors ${quantity >= (product.stockQuantity ?? product.stock) ? 'opacity-50 cursor-not-allowed' : 'hover:bg-hover'}`}
            >
              <Plus size={18} />
            </button>
          </div>

          {/* Actions */}
          <div className="flex-1 flex flex-col sm:flex-row gap-3">
            <Button
              size="lg"
              variant="outline"
              className="flex-1 border-2 border-primary text-primary hover:bg-bg-tertiary hover:text-primary transition-colors"
              onClick={handleAddToCart}
              disabled={(product.stockQuantity ?? product.stock) === 0 || isAddingToCart}
              isLoading={isAddingToCart}
              leftIcon={!isAddingToCart && <ShoppingCart size={20} />}
            >
              {t('product.addToCart')}
            </Button>
            <Button
              size="lg"
              className="flex-1 bg-slate-900 hover:bg-black text-white hover:text-white"
              onClick={onBuyNowClick}
              disabled={(product.stockQuantity ?? product.stock) === 0 || isAddingToCart}
            >
              {t('product.buyNow', 'Mua ngay')}
            </Button>
          </div>
        </div>
      )}

      {/* Contact for Quote */}
      {!hasFixedPrice && (
        <Link to={`/quote-request/${product.code}`}>
          <Button size="lg" fullWidth leftIcon={<Phone size={20} />}>
            {t('product.requestQuote')}
          </Button>
        </Link>
      )}

      {/* Secondary Actions */}
      <div className="flex flex-wrap gap-3">
        <Button
          variant={isWishlisted ? 'primary' : 'outline'}
          onClick={handleWishlistToggle}
          leftIcon={<Heart size={18} fill={isWishlisted ? 'currentColor' : 'none'} />}
        >
          {isWishlisted ? t('product.inWishlist') : t('product.addToWishlist')}
        </Button>
        <Button
          variant={isCompared ? 'primary' : 'outline'}
          onClick={handleCompareToggle}
          leftIcon={<Scale size={18} />}
        >
          {t('product.compare')}
        </Button>
        <Button 
          variant="ghost" 
          leftIcon={<Share2 size={18} />}
          onClick={() => {
            if (navigator.share) {
              navigator.share({
                title: product.name,
                text: product.description,
                url: window.location.href,
              }).catch(() => {});
            } else {
              navigator.clipboard.writeText(window.location.href);
              success(t('common.copiedToClipboard', '─É├ú sao ch├⌐p li├¬n kß║┐t'));
            }
          }}
        >
          {t('product.share')}
        </Button>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { MessageCircle, Send, User, ThumbsUp, AlertCircle } from 'lucide-react';
import { Button, Input } from '@/components/ui';
import { useToast, useAuthStore } from '@/store';
import { motion, AnimatePresence } from 'framer-motion';
import { productQAService } from '@/services/productQAService';
import { ProductQA as QAItemType } from '@/types';

interface ProductQAProps {
    productCode: string; // Ensure this is passed
}

export const ProductQA: React.FC<ProductQAProps> = ({ productCode }) => {
    const { t } = useTranslation();
    const { success, error } = useToast();
    const { isAuthenticated } = useAuthStore();
    const [questions, setQuestions] = useState<QAItemType[]>([]);
    const [answers, setAnswers] = useState<QAItemType[]>([]);
    const [newQuestion, setNewQuestion] = useState("");
    const [isAsking, setIsAsking] = useState(false);
    const [isLoading, setIsLoading] = useState(false);

    const fetchQuestions = async () => {
        if (!productCode) return;
        try {
            const data = await productQAService.getByProduct(productCode);
            if (data && Array.isArray(data)) {
                const mainQuestions = data.filter(q => !q.parentCode);
                const answerItems = data.filter(q => q.parentCode);
                setQuestions(mainQuestions);
                setAnswers(answerItems);
            }
        } catch (err) {
            console.error("Failed to fetch questions", err);
        }
    };

    useEffect(() => {
        fetchQuestions();
    }, [productCode]);

    const findAnswer = (questionCode: string) => {
        const ans = answers.find(a => a.parentCode === questionCode);
        if (ans) return ans;
        const q = questions.find(x => x.code === questionCode);
        if (q && q.replies && q.replies.length > 0) return q.replies[0];
        return null;
    };

    const handleAskClick = () => {
        if (!isAuthenticated) {
            // Option 1: Toast warning (like Reviews)
            // error(t('product.qa.loginRequired', 'Vui l├▓ng ─æ─âng nhß║¡p ─æß╗â ─æß║╖t c├óu hß╗Åi'));
            
            // Option 2: Redirect to login or open login modal (if available)
            // For now, let's stick to the toast as per ReviewButton implementation, 
            // but the user asked for "UI like reviews without login", which might just mean the visual header.
            // The ReviewButton shows the button but blocks action if not logged in.
            error(t('auth.loginRequired', 'Vui l├▓ng ─æ─âng nhß║¡p ─æß╗â thß╗▒c hiß╗çn chß╗⌐c n─âng n├áy'));
            return;
        }
        setIsAsking(!isAsking);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newQuestion.trim()) return;

        if (!isAuthenticated) {
            toast.error(t('product.qa.loginRequired'));
            return;
        }

        setIsLoading(true);
        try {
            const result = await productQAService.create(productCode, newQuestion);
            if (result) {
                toast.success(t('product.qa.submitSuccess'));
                setNewQuestion("");
                setIsAsking(false);
                fetchQuestions(); 
            }
        } catch (error) {
            toast.error(t('product.qa.submitError'));
        } finally {
            setIsLoading(false);
        }
    };

    if (!productCode) return null;

    return (
        <div className="space-y-8">
            {/* Header / Ask Box - Styled like ProductReviews */}
            <div className="bg-gradient-to-r from-indigo-50 to-purple-50 dark:from-indigo-900/20 dark:to-purple-900/20 p-6 rounded-2xl border border-indigo-100 dark:border-indigo-900/30">
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-2">
                    <div>
                        <h3 className="text-lg font-bold flex items-center gap-2 text-slate-800 dark:text-slate-200">
                            <MessageCircle className="text-indigo-600 dark:text-indigo-400" size={24} />
